import{_ as s,o as n,c as e,ag as t}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"Variables and Constants","description":"","frontmatter":{},"headers":[],"relativePath":"archive/reference/variables.md","filePath":"archive/reference/variables.md"}'),i={name:"archive/reference/variables.md"};function p(l,a,o,c,d,r){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="variables-and-constants" tabindex="-1">Variables and Constants <a class="header-anchor" href="#variables-and-constants" aria-label="Permalink to &quot;Variables and Constants&quot;">​</a></h1><p><strong>Version:</strong> 0.1.0<br><strong>Last Updated:</strong> November 3, 2025</p><p>This document defines the variable and constant declaration system in Vex, including the unified variable syntax introduced in v0.1.</p><hr><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ol><li><a href="#variable-declarations">Variable Declarations</a></li><li><a href="#constant-declarations">Constant Declarations</a></li><li><a href="#mutability-system">Mutability System</a></li><li><a href="#shadowing">Shadowing</a></li><li><a href="#scope-and-lifetime">Scope and Lifetime</a></li><li><a href="#initialization-rules">Initialization Rules</a></li><li><a href="#type-annotations">Type Annotations</a></li></ol><hr><h2 id="variable-declarations" tabindex="-1">Variable Declarations <a class="header-anchor" href="#variable-declarations" aria-label="Permalink to &quot;Variable Declarations&quot;">​</a></h2><h3 id="syntax-v0-1-unified-variable-system" tabindex="-1">Syntax v0.1: Unified Variable System <a class="header-anchor" href="#syntax-v0-1-unified-variable-system" aria-label="Permalink to &quot;Syntax v0.1: Unified Variable System&quot;">​</a></h3><p>Vex v0.1 unifies variable declarations with a single <code>let</code> keyword and explicit mutability markers:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 42;              // Immutable (default, Rust-style)</span></span>
<span class="line"><span>let! counter = 0;        // Mutable (explicit with ! suffix)</span></span></code></pre></div><p><strong>Key Changes from Previous Versions</strong>:</p><ul><li>✅ <code>let</code> for immutable variables (default)</li><li>✅ <code>let!</code> for mutable variables (explicit)</li><li>❌ <code>mut</code> keyword <strong>removed</strong> (deprecated in v0.1)</li><li>❌ <code>:=</code> operator <strong>removed</strong> (use <code>let</code> instead)</li></ul><h3 id="immutable-variables" tabindex="-1">Immutable Variables <a class="header-anchor" href="#immutable-variables" aria-label="Permalink to &quot;Immutable Variables&quot;">​</a></h3><p><strong>Syntax</strong>: <code>let name = value;</code></p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let age = 30;</span></span>
<span class="line"><span>let name = &quot;Alice&quot;;</span></span>
<span class="line"><span>let pi = 3.14159;</span></span>
<span class="line"><span>let is_valid = true;</span></span></code></pre></div><p><strong>Properties</strong>:</p><ul><li>Cannot be reassigned after initialization</li><li>Enforced by borrow checker (Phase 1: Immutability)</li><li>Default behavior (Rust-inspired)</li><li>Memory efficient (allows optimizations)</li></ul><p><strong>Example</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 42;</span></span>
<span class="line"><span>// x = 100;</span><span>  // ERROR: Cannot assign to immutable variable &#39;x&#39;</span></span></code></pre></div><h3 id="mutable-variables" tabindex="-1">Mutable Variables <a class="header-anchor" href="#mutable-variables" aria-label="Permalink to &quot;Mutable Variables&quot;">​</a></h3><p><strong>Syntax</strong>: <code>let! name = value;</code></p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! counter = 0;</span></span>
<span class="line"><span>let! balance = 1000.0;</span></span>
<span class="line"><span>let! status = true;</span></span></code></pre></div><p><strong>Properties</strong>:</p><ul><li>Can be reassigned after initialization</li><li>Requires explicit <code>let!</code> declaration</li><li>Enforced by borrow checker</li><li>Forces intentional mutability</li></ul><p><strong>Example</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! counter = 0;</span></span>
<span class="line"><span>counter = counter + 1;    // OK: counter is mutable</span></span>
<span class="line"><span>counter += 1;             // OK: compound assignment</span></span></code></pre></div><p><strong>Reassignment</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! x = 10;</span></span>
<span class="line"><span>x = 20;              // OK: x is mutable</span></span>
<span class="line"><span>x = x * 2;           // OK: 40</span></span></code></pre></div><h3 id="multiple-declarations" tabindex="-1">Multiple Declarations <a class="header-anchor" href="#multiple-declarations" aria-label="Permalink to &quot;Multiple Declarations&quot;">​</a></h3><p>Declare multiple variables in sequence:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 10;</span></span>
<span class="line"><span>let y = 20;</span></span>
<span class="line"><span>let z = 30;</span></span></code></pre></div><p><strong>Tuple Destructuring</strong> (Future):</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let (x, y, z) = (10, 20, 30);</span></span>
<span class="line"><span>let! (a, b) = (1, 2);</span></span></code></pre></div><hr><h2 id="constant-declarations" tabindex="-1">Constant Declarations <a class="header-anchor" href="#constant-declarations" aria-label="Permalink to &quot;Constant Declarations&quot;">​</a></h2><h3 id="compile-time-constants" tabindex="-1">Compile-Time Constants <a class="header-anchor" href="#compile-time-constants" aria-label="Permalink to &quot;Compile-Time Constants&quot;">​</a></h3><p><strong>Syntax</strong>: <code>const NAME = value;</code></p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const MAX_SIZE = 100;</span></span>
<span class="line"><span>const PI = 3.141592653589793;</span></span>
<span class="line"><span>const APP_NAME = &quot;VexApp&quot;;</span></span>
<span class="line"><span>const DEBUG = true;</span></span></code></pre></div><p><strong>Properties</strong>:</p><ul><li><strong>Compile-Time Evaluation</strong>: Value computed at compile time</li><li><strong>Immutable</strong>: Cannot be changed at runtime</li><li><strong>No Type Inference</strong>: Type must be determinable from literal</li><li><strong>Naming Convention</strong>: SCREAMING_SNAKE_CASE recommended</li><li><strong>Global Scope</strong>: Can be declared at module level</li></ul><p><strong>Differences from Variables</strong>:</p><table tabindex="0"><thead><tr><th>Feature</th><th><code>const</code></th><th><code>let</code></th><th><code>let!</code></th></tr></thead><tbody><tr><td>Mutability</td><td>Never</td><td>No</td><td>Yes</td></tr><tr><td>Initialization</td><td>Compile-time</td><td>Runtime</td><td>Runtime</td></tr><tr><td>Scope</td><td>Any</td><td>Block</td><td>Block</td></tr><tr><td>Memory</td><td>Inlined</td><td>Stack/Heap</td><td>Stack/Heap</td></tr><tr><td>Type Annotation</td><td>Optional</td><td>Optional</td><td>Optional</td></tr></tbody></table><p><strong>Example</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const MAX_USERS = 1000;</span></span>
<span class="line"><span>const MIN_PASSWORD_LENGTH = 8;</span></span>
<span class="line"><span>const DEFAULT_TIMEOUT = 30.0;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn validate_users(count: i32): bool {</span></span>
<span class="line"><span>    return count &lt;= MAX_USERS;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="constant-expressions" tabindex="-1">Constant Expressions <a class="header-anchor" href="#constant-expressions" aria-label="Permalink to &quot;Constant Expressions&quot;">​</a></h3><p>Constants must be initialized with compile-time constant expressions:</p><p><strong>Allowed</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const A = 42;                    // Literal</span></span>
<span class="line"><span>const B = 10 + 20;               // Arithmetic</span></span>
<span class="line"><span>const C = 100 * 2;               // Multiplication</span></span>
<span class="line"><span>const D = true &amp;&amp; false;         // Boolean logic</span></span>
<span class="line"><span>const E = &quot;Hello, &quot; + &quot;World&quot;;   // String concatenation (future)</span></span></code></pre></div><p><strong>Not Allowed</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const X = some_function();       // ERROR: Function calls</span></span>
<span class="line"><span>const Y = get_value();           // ERROR: Runtime value</span></span>
<span class="line"><span>let z = 10;</span></span>
<span class="line"><span>const Z = z + 5;                 // ERROR: Variable reference</span></span></code></pre></div><hr><h2 id="mutability-system" tabindex="-1">Mutability System <a class="header-anchor" href="#mutability-system" aria-label="Permalink to &quot;Mutability System&quot;">​</a></h2><h3 id="philosophy" tabindex="-1">Philosophy <a class="header-anchor" href="#philosophy" aria-label="Permalink to &quot;Philosophy&quot;">​</a></h3><p>Vex follows the <strong>&quot;immutable by default, mutable by choice&quot;</strong> principle:</p><ol><li><strong>Safety First</strong>: Immutability prevents accidental modifications</li><li><strong>Explicit Intent</strong>: <code>let!</code> makes mutability visible</li><li><strong>Rust-Inspired</strong>: Similar to Rust&#39;s <code>let</code> vs <code>let mut</code></li><li><strong>Borrow Checker</strong>: Enforces mutability rules at compile time</li></ol><h3 id="mutability-enforcement" tabindex="-1">Mutability Enforcement <a class="header-anchor" href="#mutability-enforcement" aria-label="Permalink to &quot;Mutability Enforcement&quot;">​</a></h3><p>The borrow checker (Phase 1) enforces mutability rules:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 42;</span></span>
<span class="line"><span>// x = 100;</span><span>  // ERROR: Cannot assign to immutable variable &#39;x&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let! y = 42;</span></span>
<span class="line"><span>y = 100;      // OK: y declared as mutable with let!</span></span></code></pre></div><p><strong>Error Message</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Borrow Checker Error: Cannot assign to immutable variable &#39;x&#39;</span></span>
<span class="line"><span>  --&gt; example.vx:3:1</span></span>
<span class="line"><span>   |</span></span>
<span class="line"><span>1  | let x = 42;</span></span>
<span class="line"><span>   |     - variable declared as immutable here</span></span>
<span class="line"><span>2  |</span></span>
<span class="line"><span>3  | x = 100;</span></span>
<span class="line"><span>   | ^^^^^^^ cannot assign to immutable variable</span></span>
<span class="line"><span>   |</span></span>
<span class="line"><span>   = help: consider declaring it as mutable: \`let! x = 42;\`</span></span></code></pre></div><h3 id="mutable-references" tabindex="-1">Mutable References <a class="header-anchor" href="#mutable-references" aria-label="Permalink to &quot;Mutable References&quot;">​</a></h3><p>The mutability of a reference is independent of the mutability of the variable it points to. Vex uses a <code>!</code> marker to denote mutable references.</p><p><strong>Syntax</strong>:</p><ul><li>Immutable Reference: <code>&amp;T</code></li><li>Mutable Reference: <code>&amp;T!</code></li></ul><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! x = 42;             // Mutable variable</span></span>
<span class="line"><span>let ref_x: &amp;i32 = &amp;x;    // Immutable reference to a mutable variable</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let! y = 100;</span></span>
<span class="line"><span>let ref_y: &amp;i32! = &amp;y;   // Mutable reference to a mutable variable</span></span></code></pre></div><p><strong>Mutability Matrix</strong>:</p><table tabindex="0"><thead><tr><th>Variable Declaration</th><th>Reference Type</th><th>Can Read?</th><th>Can Write to Variable Directly?</th><th>Can Write Through Reference?</th></tr></thead><tbody><tr><td><code>let x</code> (immutable)</td><td><code>&amp;x</code></td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td><code>let! x</code> (mutable)</td><td><code>&amp;x</code></td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td><code>let! x</code> (mutable)</td><td><code>&amp;x!</code></td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><p>This system provides fine-grained control over how data can be accessed and modified, forming a core part of Vex&#39;s safety guarantees.</p><hr><h2 id="shadowing" tabindex="-1">Shadowing <a class="header-anchor" href="#shadowing" aria-label="Permalink to &quot;Shadowing&quot;">​</a></h2><h3 id="definition" tabindex="-1">Definition <a class="header-anchor" href="#definition" aria-label="Permalink to &quot;Definition&quot;">​</a></h3><p>Shadowing allows declaring a new variable with the same name as a previous variable:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 5;</span></span>
<span class="line"><span>let x = x + 1;    // Shadows previous x</span></span>
<span class="line"><span>let x = x * 2;    // Shadows again (x is now 12)</span></span></code></pre></div><p><strong>Properties</strong>:</p><ul><li>New variable shadows the old one in the same scope</li><li>Old variable becomes inaccessible</li><li>New variable can have different type</li><li>Old variable can have different mutability</li></ul><h3 id="shadowing-vs-mutation" tabindex="-1">Shadowing vs Mutation <a class="header-anchor" href="#shadowing-vs-mutation" aria-label="Permalink to &quot;Shadowing vs Mutation&quot;">​</a></h3><p><strong>Shadowing</strong> (creates new variable):</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 5;</span></span>
<span class="line"><span>let x = x + 1;    // New immutable variable</span></span></code></pre></div><p><strong>Mutation</strong> (modifies existing variable):</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! x = 5;</span></span>
<span class="line"><span>x = x + 1;        // Modifies existing variable</span></span></code></pre></div><h3 id="type-changes-with-shadowing" tabindex="-1">Type Changes with Shadowing <a class="header-anchor" href="#type-changes-with-shadowing" aria-label="Permalink to &quot;Type Changes with Shadowing&quot;">​</a></h3><p>Shadowing allows changing the type:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = &quot;42&quot;;         // x: string</span></span>
<span class="line"><span>let x = 42;           // x: i32 (shadows previous x)</span></span></code></pre></div><p><strong>This is not possible with mutation</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! x = &quot;42&quot;;</span></span>
<span class="line"><span>// x = 42;</span><span>  // ERROR: Type mismatch (string vs i32)</span></span></code></pre></div><h3 id="scope-based-shadowing" tabindex="-1">Scope-Based Shadowing <a class="header-anchor" href="#scope-based-shadowing" aria-label="Permalink to &quot;Scope-Based Shadowing&quot;">​</a></h3><p>Inner scopes can shadow outer variables:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 10;</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>    let x = 20;   // Shadows outer x in this scope</span></span>
<span class="line"><span>    // x is 20 here</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>// x is 10 here (inner x out of scope)</span></span></code></pre></div><p><strong>Example</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn example() {</span></span>
<span class="line"><span>    let x = 5;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    if true {</span></span>
<span class="line"><span>        let x = 10;     // Shadows x in if block</span></span>
<span class="line"><span>        // x is 10 here</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // x is 5 here</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    let x = x * 2;      // Shadows x in function scope (now 10)</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="scope-and-lifetime" tabindex="-1">Scope and Lifetime <a class="header-anchor" href="#scope-and-lifetime" aria-label="Permalink to &quot;Scope and Lifetime&quot;">​</a></h2><h3 id="block-scope" tabindex="-1">Block Scope <a class="header-anchor" href="#block-scope" aria-label="Permalink to &quot;Block Scope&quot;">​</a></h3><p>Variables are scoped to the block they&#39;re declared in:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>    let x = 42;</span></span>
<span class="line"><span>    // x is accessible here</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>// x is NOT accessible here (out of scope)</span></span></code></pre></div><p><strong>Example</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn main(): i32 {</span></span>
<span class="line"><span>    let outer = 10;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>        let inner = 20;</span></span>
<span class="line"><span>        // Both outer and inner accessible</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // Only outer accessible here</span></span>
<span class="line"><span>    // inner is out of scope</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    return 0;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="function-scope" tabindex="-1">Function Scope <a class="header-anchor" href="#function-scope" aria-label="Permalink to &quot;Function Scope&quot;">​</a></h3><p>Function parameters and variables have function scope:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn calculate(x: i32, y: i32): i32 {</span></span>
<span class="line"><span>    let sum = x + y;</span></span>
<span class="line"><span>    let product = x * y;</span></span>
<span class="line"><span>    // x, y, sum, product all accessible</span></span>
<span class="line"><span>    return sum + product;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>// x, y, sum, product NOT accessible here</span></span></code></pre></div><h3 id="module-scope" tabindex="-1">Module Scope <a class="header-anchor" href="#module-scope" aria-label="Permalink to &quot;Module Scope&quot;">​</a></h3><p>Constants and functions can have module scope:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const MAX_SIZE = 100;  // Module-level constant</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn helper(): i32 {</span></span>
<span class="line"><span>    return MAX_SIZE;   // Can access module-level const</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn main(): i32 {</span></span>
<span class="line"><span>    return helper();</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="lifetime-future-feature" tabindex="-1">Lifetime (Future Feature) <a class="header-anchor" href="#lifetime-future-feature" aria-label="Permalink to &quot;Lifetime (Future Feature)&quot;">​</a></h3><p>Lifetimes track how long references are valid:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn longest&lt;&#39;a&gt;(x: &amp;&#39;a string, y: &amp;&#39;a string): &amp;&#39;a string {</span></span>
<span class="line"><span>    if x.() &gt; y.() {</span></span>
<span class="line"><span>        return x;</span></span>
<span class="line"><span>    } else {</span></span>
<span class="line"><span>        return y;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>Status</strong>: Phase 4 of borrow checker (planned)</p><hr><h2 id="initialization-rules" tabindex="-1">Initialization Rules <a class="header-anchor" href="#initialization-rules" aria-label="Permalink to &quot;Initialization Rules&quot;">​</a></h2><h3 id="must-initialize-before-use" tabindex="-1">Must Initialize Before Use <a class="header-anchor" href="#must-initialize-before-use" aria-label="Permalink to &quot;Must Initialize Before Use&quot;">​</a></h3><p>Variables must be initialized before use:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: i32;</span></span>
<span class="line"><span>// let y = x + 5;</span><span>  // ERROR: Use of uninitialized variable &#39;x&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let x = 42;</span></span>
<span class="line"><span>let y = x + 5;     // OK: x initialized</span></span></code></pre></div><h3 id="initialization-in-branches" tabindex="-1">Initialization in Branches <a class="header-anchor" href="#initialization-in-branches" aria-label="Permalink to &quot;Initialization in Branches&quot;">​</a></h3><p>Variables initialized in all branches can be used:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: i32;</span></span>
<span class="line"><span>if condition {</span></span>
<span class="line"><span>    x = 10;</span></span>
<span class="line"><span>} else {</span></span>
<span class="line"><span>    x = 20;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>// x is initialized here (both branches assign)</span></span>
<span class="line"><span>let y = x + 5;  // OK</span></span></code></pre></div><p><strong>Partial Initialization (Error)</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: i32;</span></span>
<span class="line"><span>if condition {</span></span>
<span class="line"><span>    x = 10;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>// ERROR: x may not be initialized (else branch missing)</span></span>
<span class="line"><span>// let y = x + 5;</span><span>  // ERROR</span></span></code></pre></div><h3 id="default-values" tabindex="-1">Default Values <a class="header-anchor" href="#default-values" aria-label="Permalink to &quot;Default Values&quot;">​</a></h3><p>Vex does <strong>not</strong> provide default values automatically:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// No default initialization</span></span>
<span class="line"><span>let x: i32;  // x is uninitialized (error if used)</span></span></code></pre></div><p><strong>Explicit Zero Initialization</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: i32 = 0;</span></span>
<span class="line"><span>let y: f64 = 0.0;</span></span>
<span class="line"><span>let z: bool = false;</span></span>
<span class="line"><span>let s: string = &quot;&quot;;</span></span></code></pre></div><hr><h2 id="type-annotations" tabindex="-1">Type Annotations <a class="header-anchor" href="#type-annotations" aria-label="Permalink to &quot;Type Annotations&quot;">​</a></h2><h3 id="optional-annotations" tabindex="-1">Optional Annotations <a class="header-anchor" href="#optional-annotations" aria-label="Permalink to &quot;Optional Annotations&quot;">​</a></h3><p>Type annotations are optional when type can be inferred:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 42;              // Inferred as i32</span></span>
<span class="line"><span>let y: i32 = 42;         // Explicit annotation</span></span></code></pre></div><h3 id="required-annotations" tabindex="-1">Required Annotations <a class="header-anchor" href="#required-annotations" aria-label="Permalink to &quot;Required Annotations&quot;">​</a></h3><p>Type annotations required when inference fails:</p><p><strong>Empty Collections</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// let arr = [];</span><span>         // ERROR: Cannot infer type</span></span>
<span class="line"><span>let arr: [i32; 5] = [1, 2, 3, 4, 5];  // OK</span></span></code></pre></div><p><strong>Ambiguous Numeric Types</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: u64 = 100;        // Required: could be u8, u16, u32, or u64</span></span></code></pre></div><p><strong>Function Pointers</strong> (Future):</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let f: fn(i32): i32 = some_function;</span></span></code></pre></div><h3 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h3><p>Type annotations follow the colon:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let name: Type = value;</span></span>
<span class="line"><span>let! name: Type = value;</span></span>
<span class="line"><span>const NAME: Type = value;</span></span></code></pre></div><p><strong>Examples</strong>:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let age: i32 = 30;</span></span>
<span class="line"><span>let! balance: f64 = 1000.0;</span></span>
<span class="line"><span>const MAX: u64 = 18446744073709551615;</span></span>
<span class="line"><span>let point: (i32, i32) = (10, 20);</span></span>
<span class="line"><span>let numbers: [i32; 5] = [1, 2, 3, 4, 5];</span></span></code></pre></div><hr><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><h3 id="basic-variables" tabindex="-1">Basic Variables <a class="header-anchor" href="#basic-variables" aria-label="Permalink to &quot;Basic Variables&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn main(): i32 {</span></span>
<span class="line"><span>    let x = 10;</span></span>
<span class="line"><span>    let y = 20;</span></span>
<span class="line"><span>    let sum = x + y;</span></span>
<span class="line"><span>    return sum;  // 30</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="mutable-counter" tabindex="-1">Mutable Counter <a class="header-anchor" href="#mutable-counter" aria-label="Permalink to &quot;Mutable Counter&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn count_to_ten(): i32 {</span></span>
<span class="line"><span>    let! counter = 0;</span></span>
<span class="line"><span>    while counter &lt; 10 {</span></span>
<span class="line"><span>        counter = counter + 1;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    return counter;  // 10</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="constants" tabindex="-1">Constants <a class="header-anchor" href="#constants" aria-label="Permalink to &quot;Constants&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const MAX_RETRIES = 3;</span></span>
<span class="line"><span>const TIMEOUT = 5.0;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn retry_operation(): bool {</span></span>
<span class="line"><span>    let! attempts = 0;</span></span>
<span class="line"><span>    while attempts &lt; MAX_RETRIES {</span></span>
<span class="line"><span>        if try_operation() {</span></span>
<span class="line"><span>            return true;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        attempts = attempts + 1;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    return false;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="shadowing-1" tabindex="-1">Shadowing <a class="header-anchor" href="#shadowing-1" aria-label="Permalink to &quot;Shadowing&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn transform(): i32 {</span></span>
<span class="line"><span>    let x = &quot;42&quot;;           // x: string</span></span>
<span class="line"><span>    let x = 42;             // x: i32 (shadowed)</span></span>
<span class="line"><span>    let x = x * 2;          // x: i32 = 84</span></span>
<span class="line"><span>    return x;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn scoped_example(): i32 {</span></span>
<span class="line"><span>    let outer = 10;</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>        let inner = 20;</span></span>
<span class="line"><span>        let result = outer + inner;  // 30</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    // inner not accessible here</span></span>
<span class="line"><span>    return outer;  // 10</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="comparison-with-other-languages" tabindex="-1">Comparison with Other Languages <a class="header-anchor" href="#comparison-with-other-languages" aria-label="Permalink to &quot;Comparison with Other Languages&quot;">​</a></h2><h3 id="vex-vs-rust" tabindex="-1">Vex vs Rust <a class="header-anchor" href="#vex-vs-rust" aria-label="Permalink to &quot;Vex vs Rust&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Vex v0.1</th><th>Rust</th><th>Description</th></tr></thead><tbody><tr><td><code>let x</code></td><td><code>let x</code></td><td>Immutable</td></tr><tr><td><code>let! x</code></td><td><code>let mut x</code></td><td>Mutable</td></tr><tr><td><code>const X</code></td><td><code>const X: Type</code></td><td>Constant</td></tr><tr><td><code>&amp;T!</code></td><td><code>&amp;mut T</code></td><td>Mutable reference</td></tr></tbody></table><h3 id="vex-vs-go" tabindex="-1">Vex vs Go <a class="header-anchor" href="#vex-vs-go" aria-label="Permalink to &quot;Vex vs Go&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Vex v0.1</th><th>Go</th><th>Description</th></tr></thead><tbody><tr><td><code>let x = 42</code></td><td><code>x := 42</code></td><td>Variable declaration</td></tr><tr><td><code>let! x = 42</code></td><td><code>var x = 42</code></td><td>Mutable variable</td></tr><tr><td><code>const X = 42</code></td><td><code>const X = 42</code></td><td>Constant</td></tr></tbody></table><h3 id="vex-vs-typescript" tabindex="-1">Vex vs TypeScript <a class="header-anchor" href="#vex-vs-typescript" aria-label="Permalink to &quot;Vex vs TypeScript&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Vex v0.1</th><th>TypeScript</th><th>Description</th></tr></thead><tbody><tr><td><code>let x = 42</code></td><td><code>const x = 42</code></td><td>Immutable</td></tr><tr><td><code>let! x = 42</code></td><td><code>let x = 42</code></td><td>Mutable</td></tr><tr><td><code>const X = 42</code></td><td><code>const X = 42</code></td><td>Constant</td></tr></tbody></table><hr><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><h3 id="_1-prefer-immutability" tabindex="-1">1. Prefer Immutability <a class="header-anchor" href="#_1-prefer-immutability" aria-label="Permalink to &quot;1. Prefer Immutability&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Good: Immutable by default</span></span>
<span class="line"><span>let x = 42;</span></span>
<span class="line"><span>let y = x * 2;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Only use mutable when necessary</span></span>
<span class="line"><span>let! counter = 0;</span></span>
<span class="line"><span>counter = counter + 1;</span></span></code></pre></div><h3 id="_2-use-descriptive-names" tabindex="-1">2. Use Descriptive Names <a class="header-anchor" href="#_2-use-descriptive-names" aria-label="Permalink to &quot;2. Use Descriptive Names&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Good</span></span>
<span class="line"><span>let user_count = 42;</span></span>
<span class="line"><span>let total_price = 99.99;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Bad</span></span>
<span class="line"><span>let x = 42;</span></span>
<span class="line"><span>let y = 99.99;</span></span></code></pre></div><h3 id="_3-initialize-close-to-use" tabindex="-1">3. Initialize Close to Use <a class="header-anchor" href="#_3-initialize-close-to-use" aria-label="Permalink to &quot;3. Initialize Close to Use&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Good: Initialize when needed</span></span>
<span class="line"><span>if condition {</span></span>
<span class="line"><span>    let result = expensive_computation();</span></span>
<span class="line"><span>    use_result(result);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Bad: Initialize too early</span></span>
<span class="line"><span>let result = expensive_computation();</span></span>
<span class="line"><span>if condition {</span></span>
<span class="line"><span>    use_result(result);</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_4-use-constants-for-magic-numbers" tabindex="-1">4. Use Constants for Magic Numbers <a class="header-anchor" href="#_4-use-constants-for-magic-numbers" aria-label="Permalink to &quot;4. Use Constants for Magic Numbers&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Good</span></span>
<span class="line"><span>const MAX_BUFFER_SIZE = 1024;</span></span>
<span class="line"><span>let buffer = allocate(MAX_BUFFER_SIZE);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Bad</span></span>
<span class="line"><span>let buffer = allocate(1024);  // What is 1024?</span></span></code></pre></div><h3 id="_5-minimize-mutable-state" tabindex="-1">5. Minimize Mutable State <a class="header-anchor" href="#_5-minimize-mutable-state" aria-label="Permalink to &quot;5. Minimize Mutable State&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Good: Functional style</span></span>
<span class="line"><span>fn sum(numbers: [i32; 5]): i32 {</span></span>
<span class="line"><span>    let result = 0;</span></span>
<span class="line"><span>    // Use fold/reduce (future)</span></span>
<span class="line"><span>    return result;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Bad: Excessive mutation</span></span>
<span class="line"><span>fn sum(numbers: [i32; 5]): i32 {</span></span>
<span class="line"><span>    let! result = 0;</span></span>
<span class="line"><span>    let! i = 0;</span></span>
<span class="line"><span>    while i &lt; 5 {</span></span>
<span class="line"><span>        result = result + numbers[i];</span></span>
<span class="line"><span>        i = i + 1;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    return result;</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="summary-table" tabindex="-1">Summary Table <a class="header-anchor" href="#summary-table" aria-label="Permalink to &quot;Summary Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Declaration</th><th>Syntax</th><th>Mutable?</th><th>Scope</th><th>When to Use</th></tr></thead><tbody><tr><td>Immutable Variable</td><td><code>let x = value</code></td><td>No</td><td>Block</td><td>Default choice</td></tr><tr><td>Mutable Variable</td><td><code>let! x = value</code></td><td>Yes</td><td>Block</td><td>When reassignment needed</td></tr><tr><td>Constant</td><td><code>const X = value</code></td><td>No</td><td>Module/Block</td><td>Compile-time values</td></tr><tr><td>Shadowing</td><td><code>let x = ...</code> (again)</td><td>New variable</td><td>Block</td><td>Type changes, transformations</td></tr></tbody></table><hr><p><strong>Previous</strong>: <a href="./03_Type_System">03_Type_System.md</a><br><strong>Next</strong>: <a href="./05_Functions_and_Methods">05_Functions_and_Methods.md</a></p><p><strong>Maintained by</strong>: Vex Language Team</p>`,179)])])}const b=s(i,[["render",p]]);export{u as __pageData,b as default};
